(function () {
  'use strict';

  var ID = "leadex-integration-partner";
  var NAME = "Leadex — Integration Partner";
  var SOURCE = "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>{{FULL_NAME}} — CV</title>\n  <meta name=\"description\" content=\"Leadex integration partner CV template for CV Builder\" />\n  <!--\n    CV Builder template: leadex-integration-partner\n\n    Design specification\n    - Visual source of truth: supplied Leadex Systems integration banner.\n    - The supplied raster artwork is a dedicated full-width header with no text overlay.\n    - Candidate identity and contacts are rendered in a separate HTML profile strip below the image.\n    - Palette: midnight navy, electric blue, cyan glow, white and cool slate.\n    - Layout: image header, profile strip, adaptive metrics rail, two-column dossier, technical timeline.\n    - Experience uses an on-screen vertical scroller and expands fully for print/PDF.\n    - No external fonts, scripts, stylesheets, images or CDN dependencies.\n    - All user data remains HTML generated by the existing CV Builder contract.\n    - Dynamic sections grow naturally and print without internal scroll containers.\n  -->\n  <style>\n    :root {\n      --navy-950: #020713;\n      --navy-900: #061024;\n      --navy-850: #07172f;\n      --navy-800: #0a2140;\n      --blue-600: #087cff;\n      --blue-500: #1498ff;\n      --cyan-400: #1fd7ff;\n      --cyan-300: #70e8ff;\n      --paper: #f5f8fc;\n      --paper-2: #eaf1f8;\n      --ink: #101a2c;\n      --muted: #52627a;\n      --line: #c8d7e8;\n      --white: #ffffff;\n      --shadow: 0 20px 52px rgba(3, 18, 42, .20);\n      --sans: Arial, \"Helvetica Neue\", Helvetica, sans-serif;\n      --mono: \"Courier New\", Courier, monospace;\n    }\n\n    *, *::before, *::after { box-sizing: border-box; }\n\n    html {\n      min-height: 100%;\n      background: transparent;\n      color: var(--ink);\n      font-family: var(--sans);\n      -webkit-print-color-adjust: exact;\n      print-color-adjust: exact;\n    }\n\n    body {\n      margin: 0;\n      min-height: 100%;\n      padding: 24px 0;\n      background: transparent;\n      color: var(--ink);\n      font-size: 15px;\n      line-height: 1.46;\n      overflow-wrap: anywhere;\n    }\n\n    a { color: inherit; text-decoration: none; }\n    p, h1, h2, h3, ul { margin-top: 0; }\n    .empty-safe:empty { display: none !important; }\n\n    .page {\n      position: relative;\n      width: 1120px;\n      margin: 0 auto;\n      overflow: hidden;\n      background: var(--paper);\n      box-shadow: var(--shadow);\n    }\n\n    .page::before {\n      content: \"\";\n      position: absolute;\n      inset: 0;\n      pointer-events: none;\n      opacity: .36;\n      background-image:\n        linear-gradient(rgba(12,44,82,.025) 1px, transparent 1px),\n        linear-gradient(90deg, rgba(12,44,82,.025) 1px, transparent 1px);\n      background-size: 24px 24px;\n      z-index: 0;\n    }\n\n    .document { position: relative; z-index: 1; }\n\n    /* Header -------------------------------------------------- */\n    .hero {\n      position: relative;\n      aspect-ratio: 1536 / 634;\n      overflow: hidden;\n      color: var(--white);\n      background-image:\n        linear-gradient(180deg, rgba(0,4,13,.22), rgba(0,5,16,.02) 52%, rgba(0,6,20,.34)),\n        url(\"data:image/webp;base64,\");\n      background-size: cover;\n      background-position: center;\n      background-repeat: no-repeat;\n      isolation: isolate;\n    }\n\n    .hero::after {\n      content: \"\";\n      position: absolute;\n      inset: 0;\n      z-index: -1;\n      pointer-events: none;\n      box-shadow: inset 0 -42px 70px rgba(0,5,18,.58), inset 0 0 0 1px rgba(83,201,255,.18);\n    }\n\n    .hero-live-data {\n      display: flex;\n      align-items: flex-start;\n      justify-content: space-between;\n      gap: 24px;\n      padding: 24px 28px;\n    }\n\n    .identity-card,\n    .contact-card {\n      border: 1px solid rgba(89,205,255,.42);\n      background: linear-gradient(135deg, rgba(2,10,26,.88), rgba(4,19,45,.70));\n      box-shadow: 0 14px 32px rgba(0,0,0,.28), inset 0 0 26px rgba(24,143,255,.06);\n      backdrop-filter: blur(4px);\n    }\n\n    .identity-card {\n      width: min(650px, 64%);\n      padding: 18px 22px 17px;\n      border-left: 4px solid var(--cyan-400);\n    }\n\n    .hero-kicker {\n      margin: 0 0 7px;\n      color: var(--cyan-300);\n      font: 700 12px/1 var(--mono);\n      letter-spacing: .18em;\n      text-transform: uppercase;\n    }\n\n    .full-name {\n      margin: 0;\n      color: var(--white);\n      font-size: clamp(30px, 4.15vw, 55px);\n      font-weight: 800;\n      line-height: .98;\n      letter-spacing: -.025em;\n      text-shadow: 0 0 24px rgba(20,152,255,.46);\n    }\n\n    .role-title {\n      margin: 9px 0 0;\n      color: #cfefff;\n      font-size: 20px;\n      font-weight: 700;\n      line-height: 1.18;\n    }\n\n    .specialization-line {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 7px 12px;\n      margin: 9px 0 0;\n      color: #a5bcd4;\n      font-size: 12px;\n      font-weight: 700;\n      letter-spacing: .08em;\n      text-transform: uppercase;\n    }\n\n    .specialization-line span:not(:empty) + span:not(:empty)::before {\n      content: \"//\";\n      margin-right: 12px;\n      color: var(--cyan-400);\n    }\n\n    .contact-card {\n      width: 290px;\n      padding: 14px 16px;\n      font-size: 12px;\n      line-height: 1.25;\n    }\n\n    .contact-title {\n      margin: 0 0 9px;\n      color: var(--cyan-300);\n      font: 700 11px/1 var(--mono);\n      letter-spacing: .14em;\n      text-transform: uppercase;\n    }\n\n    .contact-list {\n      display: grid;\n      gap: 6px;\n    }\n\n    .contact-line {\n      display: grid;\n      grid-template-columns: 72px minmax(0, 1fr);\n      gap: 8px;\n      min-width: 0;\n    }\n\n    .contact-label {\n      color: #75a0c4;\n      font-family: var(--mono);\n      text-transform: uppercase;\n    }\n\n    .contact-value { color: #f5fbff; text-align: right; }\n    .contact-line:has(.contact-value:empty) { display: none; }\n\n    /* Dedicated profile strip below the image header --------- */\n    .profile-header {\n      position: relative;\n      background:\n        radial-gradient(circle at 100% 0, rgba(20,152,255,.08), transparent 36%),\n        linear-gradient(180deg, #ffffff, #f4f8fc);\n      border-top: 2px solid #159fe8;\n      border-bottom: 1px solid var(--line);\n    }\n\n    .profile-header .hero-live-data {\n      display: grid;\n      grid-template-columns: minmax(0, 1.08fr) minmax(330px, .92fr);\n      align-items: stretch;\n      gap: 28px;\n      padding: 22px 30px 20px;\n    }\n\n    .profile-header .identity-card,\n    .profile-header .contact-card {\n      width: auto;\n      color: var(--ink);\n      border: 0;\n      border-radius: 0;\n      background: transparent;\n      box-shadow: none;\n      backdrop-filter: none;\n    }\n\n    .profile-header .identity-card {\n      padding: 0 28px 0 0;\n      border-right: 1px solid var(--line);\n      border-left: 0;\n    }\n\n    .profile-header .contact-card {\n      padding: 2px 0 0;\n      font-size: 13px;\n      line-height: 1.3;\n    }\n\n    .profile-header .hero-kicker {\n      margin-bottom: 8px;\n      color: #1375b6;\n    }\n\n    .profile-header .full-name {\n      color: #111c31;\n      font-size: clamp(32px, 4vw, 48px);\n      line-height: 1;\n      text-shadow: none;\n    }\n\n    .profile-header .role-title {\n      margin-top: 10px;\n      color: #0967b4;\n      font-size: 20px;\n    }\n\n    .profile-header .specialization-line {\n      margin-top: 11px;\n      color: #5a6f88;\n    }\n\n    .profile-header .contact-title {\n      margin-bottom: 12px;\n      color: #0875bb;\n    }\n\n    .profile-header .contact-list { gap: 8px; }\n\n    .profile-header .contact-line {\n      grid-template-columns: 82px minmax(0, 1fr);\n      gap: 12px;\n    }\n\n    .profile-header .contact-label {\n      color: #58708a;\n      font-weight: 700;\n    }\n\n    .profile-header .contact-value {\n      color: #162842;\n      text-align: left;\n      overflow-wrap: anywhere;\n    }\n\n    /* Metrics ------------------------------------------------- */\n    .metrics-rail {\n      position: relative;\n      padding: 15px 22px;\n      background:\n        linear-gradient(90deg, rgba(20,152,255,.10), transparent 18%, transparent 82%, rgba(31,215,255,.08)),\n        var(--navy-900);\n      border-top: 1px solid #1469b5;\n      border-bottom: 1px solid #114e87;\n    }\n\n    .metrics-list {\n      display: grid;\n      grid-template-columns: repeat(4, minmax(0, 1fr));\n      gap: 10px;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .metric-item {\n      position: relative;\n      min-width: 0;\n      min-height: 74px;\n      padding: 12px 13px 10px;\n      border: 1px solid rgba(47,181,255,.28);\n      background: linear-gradient(145deg, rgba(7,35,69,.95), rgba(3,16,37,.95));\n      break-inside: avoid;\n    }\n\n    .metric-item::before {\n      content: \"\";\n      position: absolute;\n      left: -1px;\n      top: 14px;\n      bottom: 14px;\n      width: 3px;\n      background: var(--cyan-400);\n      box-shadow: 0 0 12px rgba(31,215,255,.7);\n    }\n\n    .metric-value {\n      display: block;\n      color: var(--white);\n      font-size: 25px;\n      font-weight: 800;\n      line-height: 1;\n    }\n\n    .metric-label {\n      display: block;\n      margin-top: 7px;\n      color: #83b9dd;\n      font: 700 10px/1.2 var(--mono);\n      letter-spacing: .09em;\n      text-transform: uppercase;\n    }\n\n    /* Content ------------------------------------------------- */\n    .content-wrap { padding: 22px; }\n\n    .section-card {\n      position: relative;\n      min-width: 0;\n      border: 1px solid var(--line);\n      background: rgba(255,255,255,.86);\n      box-shadow: 0 8px 22px rgba(12,42,74,.07);\n      break-inside: avoid;\n    }\n\n    .section-card + .section-card { margin-top: 14px; }\n\n    .section-heading {\n      display: flex;\n      align-items: center;\n      gap: 12px;\n      margin: 0;\n      padding: 12px 15px 11px;\n      color: var(--white);\n      background:\n        linear-gradient(90deg, rgba(20,152,255,.22), transparent 40%),\n        var(--navy-850);\n      font-size: 17px;\n      font-weight: 800;\n      line-height: 1;\n      letter-spacing: .08em;\n      text-transform: uppercase;\n    }\n\n    .section-heading::before {\n      content: \"\";\n      flex: 0 0 27px;\n      height: 3px;\n      background: var(--cyan-400);\n      box-shadow: 0 0 10px rgba(31,215,255,.65);\n    }\n\n    .section-body { padding: 16px; }\n\n    .summary-card { margin-bottom: 16px; }\n    .short-summary {\n      margin: 0;\n      color: #20334d;\n      font-size: 20px;\n      font-weight: 700;\n      line-height: 1.42;\n      white-space: pre-line;\n    }\n\n    .short-summary:empty { display: none; }\n\n    .professional-summary {\n      margin: 12px 0 0;\n      padding-top: 12px;\n      border-top: 1px solid var(--line);\n      color: var(--muted);\n      font-size: 14px;\n      line-height: 1.62;\n      white-space: pre-line;\n    }\n\n    .main-grid {\n      display: grid;\n      grid-template-columns: minmax(0, 2.15fr) minmax(270px, .85fr);\n      gap: 16px;\n      align-items: start;\n    }\n\n    .main-column,\n    .sidebar { min-width: 0; }\n\n    .sidebar { display: grid; gap: 14px; }\n    .sidebar .section-card + .section-card { margin-top: 0; }\n    .sidebar .section-heading { font-size: 14px; padding: 11px 13px 10px; }\n    .sidebar .section-heading::before { flex-basis: 19px; }\n    .sidebar .section-body { padding: 13px; }\n\n    /* Skills -------------------------------------------------- */\n    .skill-list {\n      display: flex;\n      flex-wrap: wrap;\n      gap: 7px;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .skill-item {\n      max-width: 100%;\n      padding: 6px 9px;\n      border: 1px solid #a9c9e4;\n      color: #153c66;\n      background: linear-gradient(180deg, #f8fcff, #e8f3fc);\n      font-size: 12px;\n      font-weight: 700;\n      line-height: 1.2;\n      break-inside: avoid;\n    }\n\n    /* Industries ---------------------------------------------- */\n    .industry-list {\n      display: grid;\n      gap: 10px;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .industry-item {\n      display: grid;\n      grid-template-columns: 38px minmax(0, 1fr);\n      gap: 9px;\n      align-items: start;\n      break-inside: avoid;\n    }\n\n    .industry-media {\n      display: grid;\n      place-items: center;\n      width: 36px;\n      height: 36px;\n      border: 1px solid #53bdf4;\n      color: var(--white);\n      background: linear-gradient(145deg, var(--blue-600), #07447d);\n      font: 800 16px/1 var(--mono);\n      box-shadow: 0 0 14px rgba(20,152,255,.18);\n    }\n\n    .industry-title {\n      display: block;\n      color: #153756;\n      font-size: 13px;\n      font-weight: 800;\n      line-height: 1.2;\n      text-transform: uppercase;\n    }\n\n    .industry-description {\n      display: block;\n      margin-top: 3px;\n      color: var(--muted);\n      font-size: 12px;\n      line-height: 1.35;\n    }\n\n    /* Simple sidebar lists ------------------------------------ */\n    .simple-list {\n      display: grid;\n      gap: 8px;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .simple-item {\n      position: relative;\n      padding-left: 15px;\n      color: #31465f;\n      font-size: 12px;\n      line-height: 1.42;\n      break-inside: avoid;\n    }\n\n    .simple-item::before {\n      content: \"\";\n      position: absolute;\n      left: 0;\n      top: .58em;\n      width: 6px;\n      height: 6px;\n      border: 1px solid var(--blue-500);\n      transform: rotate(45deg);\n      background: #dff7ff;\n    }\n\n    /* Experience ---------------------------------------------- */\n    .experience-card { break-inside: auto; }\n    .experience-list {\n      position: relative;\n      display: grid;\n      gap: 0;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .experience-list::before {\n      content: \"\";\n      position: absolute;\n      left: 106px;\n      top: 12px;\n      bottom: 12px;\n      width: 1px;\n      background: linear-gradient(var(--blue-500), #aac7df 86%, transparent);\n    }\n\n    .experience-item {\n      position: relative;\n      display: grid;\n      grid-template-columns: 94px minmax(0, 1fr);\n      gap: 27px;\n      padding: 15px 0;\n      border-bottom: 1px solid var(--line);\n      break-inside: avoid;\n    }\n\n    .experience-item:first-child { padding-top: 2px; }\n    .experience-item:last-child { padding-bottom: 2px; border-bottom: 0; }\n\n    .experience-date {\n      align-self: start;\n      padding: 7px 7px 6px;\n      border: 1px solid #70bdea;\n      color: #13558a;\n      background: #eff9ff;\n      font: 700 10px/1.28 var(--mono);\n      text-align: center;\n      text-transform: uppercase;\n    }\n\n    .experience-content { position: relative; min-width: 0; }\n    .experience-content::before {\n      content: \"\";\n      position: absolute;\n      left: -31px;\n      top: 10px;\n      width: 8px;\n      height: 8px;\n      border: 2px solid var(--paper);\n      border-radius: 50%;\n      background: var(--cyan-400);\n      box-shadow: 0 0 0 2px var(--blue-500), 0 0 12px rgba(31,215,255,.55);\n    }\n\n    .experience-position {\n      margin: 0;\n      color: #102a48;\n      font-size: 19px;\n      font-weight: 800;\n      line-height: 1.15;\n    }\n\n    .experience-company {\n      margin: 5px 0 8px;\n      color: #1c75b6;\n      font: 700 11px/1.25 var(--mono);\n      letter-spacing: .025em;\n      text-transform: uppercase;\n    }\n\n    .achievement-list,\n    .tech-bullets {\n      margin: 0;\n      padding-left: 18px;\n      color: #43566d;\n      font-size: 13px;\n      line-height: 1.48;\n    }\n\n    .achievement-list li,\n    .tech-bullets li { margin: 4px 0; }\n    .achievement-list li::marker,\n    .tech-bullets li::marker { color: var(--blue-500); }\n\n    .experience-scroll {\n      max-height: 620px;\n      overflow-y: auto;\n      overflow-x: hidden;\n      overscroll-behavior: contain;\n      scrollbar-gutter: stable;\n      padding-right: 12px;\n      scroll-behavior: smooth;\n      scrollbar-width: thin;\n      scrollbar-color: #169be2 #e3edf6;\n    }\n\n    .experience-scroll::-webkit-scrollbar { width: 10px; }\n    .experience-scroll::-webkit-scrollbar-track {\n      background: #e3edf6;\n      border-left: 1px solid #cad9e8;\n    }\n    .experience-scroll::-webkit-scrollbar-thumb {\n      min-height: 54px;\n      border: 2px solid #e3edf6;\n      border-radius: 10px;\n      background: linear-gradient(180deg, #20cfff, #0878cb);\n    }\n    .experience-scroll::-webkit-scrollbar-thumb:hover {\n      background: linear-gradient(180deg, #44dcff, #0869b3);\n    }\n\n    /* Projects ------------------------------------------------ */\n    .project-list {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 10px;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .project-item {\n      min-width: 0;\n      padding: 13px;\n      border: 1px solid #bad2e6;\n      background:\n        linear-gradient(135deg, rgba(20,152,255,.055), transparent 52%),\n        #fbfdff;\n      break-inside: avoid;\n    }\n\n    .project-name {\n      margin: 0;\n      color: #0e4675;\n      font-size: 14px;\n      font-weight: 800;\n      line-height: 1.22;\n      text-transform: uppercase;\n    }\n\n    .project-description {\n      margin: 7px 0 0;\n      color: var(--muted);\n      font-size: 12px;\n      line-height: 1.46;\n      white-space: pre-line;\n    }\n\n    /* Technical expertise ------------------------------------- */\n    .tech-list {\n      display: grid;\n      grid-template-columns: repeat(2, minmax(0, 1fr));\n      gap: 10px;\n      margin: 0;\n      padding: 0;\n      list-style: none;\n    }\n\n    .tech-panel {\n      min-width: 0;\n      padding: 13px;\n      border: 1px solid #adcbe1;\n      background: linear-gradient(180deg, #f9fcff, #edf6fc);\n      break-inside: avoid;\n    }\n\n    .tech-title {\n      margin: 0 0 8px;\n      color: #123e66;\n      font-size: 14px;\n      font-weight: 800;\n      line-height: 1.2;\n      text-transform: uppercase;\n    }\n\n    .tech-bullets { font-size: 12px; padding-left: 17px; }\n\n    /* Footer -------------------------------------------------- */\n    .site-footer {\n      position: relative;\n      display: grid;\n      grid-template-columns: minmax(0, 1.5fr) minmax(250px, .8fr);\n      gap: 20px;\n      align-items: center;\n      margin-top: 18px;\n      padding: 18px 22px;\n      color: var(--white);\n      background:\n        radial-gradient(circle at 18% 50%, rgba(20,152,255,.26), transparent 34%),\n        linear-gradient(120deg, #030a19, #071a35 60%, #031225);\n      border-top: 2px solid var(--blue-500);\n      break-inside: avoid;\n    }\n\n    .site-footer::after {\n      content: \"\";\n      position: absolute;\n      right: 0;\n      top: 0;\n      width: 34%;\n      height: 100%;\n      opacity: .22;\n      background-image:\n        linear-gradient(rgba(31,215,255,.25) 1px, transparent 1px),\n        linear-gradient(90deg, rgba(31,215,255,.25) 1px, transparent 1px);\n      background-size: 18px 18px;\n      mask-image: linear-gradient(90deg, transparent, #000);\n      pointer-events: none;\n    }\n\n    .footer-tagline {\n      position: relative;\n      z-index: 1;\n      margin: 0;\n      color: #d9f6ff;\n      font-size: 21px;\n      font-weight: 800;\n      line-height: 1.15;\n      letter-spacing: .02em;\n      text-transform: uppercase;\n    }\n\n    .additional-note {\n      position: relative;\n      z-index: 1;\n      margin: 0;\n      padding-left: 13px;\n      border-left: 2px solid var(--cyan-400);\n      color: #99b8d2;\n      font-size: 12px;\n      line-height: 1.45;\n      white-space: pre-line;\n    }\n\n    @media (max-width: 900px) {\n      body { padding: 0; }\n      .page { width: 100%; }\n      .hero-live-data { padding: 18px; }\n      .identity-card { width: 62%; }\n      .contact-card { width: 270px; }\n      .metrics-list { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n      .main-grid { grid-template-columns: minmax(0, 1fr); }\n      .sidebar { grid-template-columns: repeat(2, minmax(0, 1fr)); }\n    }\n\n    @media (max-width: 680px) {\n      .hero { aspect-ratio: 1536 / 634; min-height: 0; background-position: center; }\n      .profile-header .hero-live-data { grid-template-columns: minmax(0, 1fr); gap: 16px; }\n      .profile-header .identity-card { padding: 0 0 16px; border-right: 0; border-bottom: 1px solid var(--line); }\n      .profile-header .contact-card { padding: 0; }\n      .identity-card, .contact-card { width: 100%; }\n      .contact-value { text-align: left; }\n      .experience-scroll { max-height: 560px; }\n      .content-wrap { padding: 12px; }\n      .metrics-rail { padding: 12px; }\n      .metrics-list { grid-template-columns: minmax(0, 1fr); }\n      .sidebar { grid-template-columns: minmax(0, 1fr); }\n      .project-list, .tech-list { grid-template-columns: minmax(0, 1fr); }\n      .experience-list::before { left: 10px; }\n      .experience-item { grid-template-columns: minmax(0, 1fr); gap: 8px; padding-left: 25px; }\n      .experience-date { justify-self: start; }\n      .experience-content::before { left: -19px; top: 8px; }\n      .site-footer { grid-template-columns: minmax(0, 1fr); }\n    }\n\n    @page { size: A4; margin: 0; }\n\n    @media print {\n      html, body { background: #fff; }\n      body { padding: 0; }\n      .page { width: 210mm; margin: 0; box-shadow: none; }\n      .hero { break-inside: avoid; }\n      .profile-header .hero-live-data { padding: 5mm 6mm; }\n      .profile-header .identity-card { padding: 0 5mm 0 0; }\n      .profile-header .contact-card { padding: 0; }\n      .content-wrap { padding: 4.5mm; }\n      .metrics-rail { padding: 3.2mm 4.5mm; }\n      .section-card { box-shadow: none; }\n      .experience-card { break-inside: auto; }\n      .experience-scroll { max-height: none; overflow: visible; padding-right: 0; scrollbar-gutter: auto; }\n      .experience-item, .project-item, .tech-panel, .industry-item, .metric-item { break-inside: avoid; }\n      .section-heading { break-after: avoid; }\n      .site-footer { margin-top: 4mm; }\n    }\n  </style>\n</head>\n<body>\n  <main class=\"page\">\n    <div class=\"document\">\n      <header class=\"hero\" aria-label=\"Leadex Systems integration partner header\"></header>\n\n      <section class=\"profile-header\" aria-label=\"Candidate profile header\">\n        <div class=\"hero-live-data\">\n          <section class=\"identity-card\" aria-label=\"Candidate identity\">\n            <p class=\"hero-kicker\">{{PRIMARY_DOMAIN}}</p>\n            <h1 class=\"full-name\">{{FULL_NAME}}</h1>\n            <p class=\"role-title\">{{ROLE_TITLE}}</p>\n            <p class=\"specialization-line\">\n              <span>{{SPECIALIZATION}}</span>\n              <span>{{LOCATION}}</span>\n            </p>\n          </section>\n\n          <aside class=\"contact-card\" aria-label=\"Contact information\">\n            <p class=\"contact-title\">Connection endpoint</p>\n            <div class=\"contact-list\">\n              <div class=\"contact-line\"><span class=\"contact-label\">Email</span><span class=\"contact-value\">{{EMAIL}}</span></div>\n              <div class=\"contact-line\"><span class=\"contact-label\">Phone</span><span class=\"contact-value\">{{PHONE}}</span></div>\n              <div class=\"contact-line\"><span class=\"contact-label\">LinkedIn</span><span class=\"contact-value\">{{LINKEDIN_URL}}</span></div>\n              <div class=\"contact-line\"><span class=\"contact-label\">Location</span><span class=\"contact-value\">{{CITY_COUNTRY}}</span></div>\n            </div>\n          </aside>\n        </div>\n      </section>\n\n      <!--CVB:section metrics-->\n      <section class=\"metrics-rail\" aria-label=\"Professional metrics\">\n        <ul class=\"metrics-list\">\n          <!--CVB:repeat metrics-->\n          <li class=\"metric-item\" data-cvb-kind=\"metrics\">\n            <span class=\"metric-value\">{{VALUE}}</span>\n            <span class=\"metric-label\">{{LABEL}}</span>\n          </li>\n          <!--CVB:endrepeat metrics-->\n        </ul>\n      </section>\n      <!--CVB:endsection metrics-->\n\n      <div class=\"content-wrap\">\n        <section class=\"section-card summary-card\" data-summary-card>\n          <h2 class=\"section-heading\">Executive profile</h2>\n          <div class=\"section-body\">\n            <p class=\"short-summary\">{{SHORT_PROFILE_SUMMARY}}</p>\n            <!--CVB:section professionalSummary-->\n            <p class=\"professional-summary\">{{PROFESSIONAL_SUMMARY}}</p>\n            <!--CVB:endsection professionalSummary-->\n          </div>\n        </section>\n\n        <div class=\"main-grid\">\n          <div class=\"main-column\">\n            <!--CVB:section experience-->\n            <section class=\"section-card experience-card\">\n              <h2 class=\"section-heading\">Experience timeline</h2>\n              <div class=\"section-body experience-scroll\" tabindex=\"0\" aria-label=\"Scrollable work experience\">\n                <ol class=\"experience-list\">\n                  <!--CVB:repeat experience-->\n                  <li class=\"experience-item\" data-cvb-kind=\"experience\">\n                    <div class=\"experience-date\"><span>{{DATE_FROM}}</span><br /><span>{{DATE_TO}}</span></div>\n                    <div class=\"experience-content\">\n                      <h3 class=\"experience-position\">{{POSITION}}</h3>\n                      <!--CVB:section experienceCompany-->\n                      <p class=\"experience-company\">{{COMPANY_LINE}}</p>\n                      <!--CVB:endsection experienceCompany-->\n                      <ul class=\"achievement-list\">\n                        <!--CVB:repeat achievements-->\n                        <li>{{TEXT}}</li>\n                        <!--CVB:endrepeat achievements-->\n                      </ul>\n                    </div>\n                  </li>\n                  <!--CVB:endrepeat experience-->\n                </ol>\n              </div>\n            </section>\n            <!--CVB:endsection experience-->\n\n            <!--CVB:section projects-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Selected solutions</h2>\n              <div class=\"section-body\">\n                <ul class=\"project-list\">\n                  <!--CVB:repeat projects-->\n                  <li class=\"project-item\" data-cvb-kind=\"projects\">\n                    <h3 class=\"project-name\">{{NAME}}</h3>\n                    <!--CVB:section projectDesc-->\n                    <p class=\"project-description\">{{DESCRIPTION}}</p>\n                    <!--CVB:endsection projectDesc-->\n                  </li>\n                  <!--CVB:endrepeat projects-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection projects-->\n\n            <!--CVB:section techPanels-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Technical expertise</h2>\n              <div class=\"section-body\">\n                <ul class=\"tech-list\">\n                  <!--CVB:repeat techPanels-->\n                  <li class=\"tech-panel\" data-cvb-kind=\"techPanels\">\n                    <h3 class=\"tech-title\">{{TITLE}}</h3>\n                    <ul class=\"tech-bullets\">\n                      <!--CVB:repeat techBullets-->\n                      <li>{{TEXT}}</li>\n                      <!--CVB:endrepeat techBullets-->\n                    </ul>\n                  </li>\n                  <!--CVB:endrepeat techPanels-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection techPanels-->\n          </div>\n\n          <aside class=\"sidebar\">\n            <!--CVB:section skills-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Core capabilities</h2>\n              <div class=\"section-body\">\n                <ul class=\"skill-list\">\n                  <!--CVB:repeat skills-->\n                  <li class=\"skill-item\" data-cvb-kind=\"skills\">{{LABEL}}</li>\n                  <!--CVB:endrepeat skills-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection skills-->\n\n            <!--CVB:section industries-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Industries</h2>\n              <div class=\"section-body\">\n                <ul class=\"industry-list\">\n                  <!--CVB:repeat industries-->\n                  <li class=\"industry-item\" data-cvb-kind=\"industries\">\n                    <span class=\"industry-media\">{{MEDIA}}</span>\n                    <span>\n                      <strong class=\"industry-title\">{{TITLE}}</strong>\n                      <!--CVB:section industryDesc-->\n                      <span class=\"industry-description\">{{DESCRIPTION}}</span>\n                      <!--CVB:endsection industryDesc-->\n                    </span>\n                  </li>\n                  <!--CVB:endrepeat industries-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection industries-->\n\n            <!--CVB:section certifications-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Certifications</h2>\n              <div class=\"section-body\">\n                <ul class=\"simple-list\">\n                  <!--CVB:repeat certifications-->\n                  <li class=\"simple-item\" data-cvb-kind=\"certifications\">{{TITLE}}</li>\n                  <!--CVB:endrepeat certifications-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection certifications-->\n\n            <!--CVB:section education-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Education</h2>\n              <div class=\"section-body\">\n                <ul class=\"simple-list\">\n                  <!--CVB:repeat education-->\n                  <li class=\"simple-item\" data-cvb-kind=\"education\">{{LINE}}</li>\n                  <!--CVB:endrepeat education-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection education-->\n\n            <!--CVB:section languages-->\n            <section class=\"section-card\">\n              <h2 class=\"section-heading\">Languages</h2>\n              <div class=\"section-body\">\n                <ul class=\"simple-list\">\n                  <!--CVB:repeat languages-->\n                  <li class=\"simple-item\" data-cvb-kind=\"languages\">{{LINE}}</li>\n                  <!--CVB:endrepeat languages-->\n                </ul>\n              </div>\n            </section>\n            <!--CVB:endsection languages-->\n          </aside>\n        </div>\n\n        <footer class=\"site-footer\" data-template-footer>\n          <p class=\"footer-tagline\">{{FOOTER_TAGLINE}}</p>\n          <p class=\"additional-note\">{{ADDITIONAL_NOTE}}</p>\n        </footer>\n      </div>\n    </div>\n  </main>\n</body>\n</html>\n";

  function ownText(value) {
    return value === 0 ? '0' : (value == null ? '' : String(value));
  }

  function defaultEsc(value) {
    return ownText(value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function defaultFillTokens(text, values) {
    return String(text).replace(/\{\{([A-Z0-9_]+)\}\}/g, function (_, key) {
      return Object.prototype.hasOwnProperty.call(values, key) ? ownText(values[key]) : '';
    });
  }

  function blockPattern(type, name) {
    return new RegExp('<!--CVB:' + type + ' ' + name + '-->([\\s\\S]*?)<!--CVB:end' + type + ' ' + name + '-->', 'g');
  }

  function defaultExpandSection(text, name, enabled, renderBody) {
    return String(text).replace(blockPattern('section', name), function (_, body) {
      return enabled ? renderBody(body) : '';
    });
  }

  function defaultExpandRepeat(text, name, items, renderUnit) {
    return String(text).replace(blockPattern('repeat', name), function (_, unit) {
      return items.map(function (item, index) { return renderUnit(unit, item, index); }).join('');
    });
  }

  function array(value) { return Array.isArray(value) ? value : []; }
  function hasText(value) { return ownText(value).trim().length > 0; }
  function joinParts(parts) { return parts.filter(hasText).map(ownText).join(' · '); }

  function render(data, ctx) {
    data = data || {};
    ctx = ctx || {};

    var esc = typeof ctx.esc === 'function' ? ctx.esc : defaultEsc;
    var fillTokens = typeof ctx.fillTokens === 'function' ? ctx.fillTokens : defaultFillTokens;
    var expandRepeat = typeof ctx.expandRepeat === 'function' ? ctx.expandRepeat : defaultExpandRepeat;
    var expandSection = typeof ctx.expandSection === 'function' ? ctx.expandSection : defaultExpandSection;
    var html = SOURCE;
    var personal = data.personal || {};

    var metrics = array(data.metrics);
    html = expandSection(html, 'metrics', metrics.length > 0, function (body) {
      return expandRepeat(body, 'metrics', metrics, function (unit, item) {
        item = item || {};
        return fillTokens(unit, { LABEL: esc(item.label), VALUE: esc(item.value) });
      });
    });

    var skills = array(data.skills);
    html = expandSection(html, 'skills', skills.length > 0, function (body) {
      return expandRepeat(body, 'skills', skills, function (unit, item) {
        return fillTokens(unit, { LABEL: esc(item && item.label) });
      });
    });

    var industries = array(data.industries);
    html = expandSection(html, 'industries', industries.length > 0, function (body) {
      return expandRepeat(body, 'industries', industries, function (unit, item) {
        item = item || {};
        var title = ownText(item.title).trim();
        var media = title ? title.charAt(0).toUpperCase() : '?';
        unit = expandSection(unit, 'industryDesc', hasText(item.description), function (descriptionBody) {
          return fillTokens(descriptionBody, { DESCRIPTION: esc(item.description) });
        });
        return fillTokens(unit, { MEDIA: esc(media), TITLE: esc(title) });
      });
    });

    var certifications = array(data.certifications);
    html = expandSection(html, 'certifications', certifications.length > 0, function (body) {
      return expandRepeat(body, 'certifications', certifications, function (unit, item) {
        return fillTokens(unit, { TITLE: esc(item && item.title) });
      });
    });

    var education = array(data.education);
    html = expandSection(html, 'education', education.length > 0, function (body) {
      return expandRepeat(body, 'education', education, function (unit, item) {
        item = item || {};
        return fillTokens(unit, { LINE: esc(joinParts([item.title, item.org, item.year])) });
      });
    });

    var languages = array(data.languages);
    html = expandSection(html, 'languages', languages.length > 0, function (body) {
      return expandRepeat(body, 'languages', languages, function (unit, item) {
        item = item || {};
        return fillTokens(unit, { LINE: esc(joinParts([item.name, item.level])) });
      });
    });

    html = expandSection(html, 'professionalSummary', hasText(personal.professionalSummary), function (body) {
      return fillTokens(body, { PROFESSIONAL_SUMMARY: esc(personal.professionalSummary) });
    });

    var experience = array(data.experience);
    html = expandSection(html, 'experience', experience.length > 0, function (body) {
      return expandRepeat(body, 'experience', experience, function (unit, item) {
        item = item || {};
        var companyLine = joinParts([item.company, item.location]);
        unit = expandSection(unit, 'experienceCompany', hasText(companyLine), function (companyBody) {
          return fillTokens(companyBody, { COMPANY_LINE: esc(companyLine) });
        });
        unit = expandRepeat(unit, 'achievements', array(item.achievements), function (achievementUnit, achievement) {
          return fillTokens(achievementUnit, { TEXT: esc(achievement && achievement.text) });
        });
        return fillTokens(unit, {
          POSITION: esc(item.position),
          DATE_FROM: esc(item.dateFrom),
          DATE_TO: esc(item.dateTo)
        });
      });
    });

    var projects = array(data.projects);
    html = expandSection(html, 'projects', projects.length > 0, function (body) {
      return expandRepeat(body, 'projects', projects, function (unit, item) {
        item = item || {};
        unit = expandSection(unit, 'projectDesc', hasText(item.description), function (descriptionBody) {
          return fillTokens(descriptionBody, { DESCRIPTION: esc(item.description) });
        });
        return fillTokens(unit, { NAME: esc(item.name) });
      });
    });

    var techPanels = array(data.techPanels);
    html = expandSection(html, 'techPanels', techPanels.length > 0, function (body) {
      return expandRepeat(body, 'techPanels', techPanels, function (unit, item) {
        item = item || {};
        unit = expandRepeat(unit, 'techBullets', array(item.bullets), function (bulletUnit, bullet) {
          return fillTokens(bulletUnit, { TEXT: esc(bullet && bullet.text) });
        });
        return fillTokens(unit, { TITLE: esc(item.title) });
      });
    });

    if (!hasText(personal.shortProfileSummary) && !hasText(personal.professionalSummary)) {
      html = html.replace(/\s*<section class="section-card summary-card"[\s\S]*?<\/section>\s*/, '');
    }
    if (!hasText(personal.footerTagline) && !hasText(personal.additionalNote)) {
      html = html.replace(/\s*<footer class="site-footer"[\s\S]*?<\/footer>\s*/, '');
    }

    html = fillTokens(html, {
      FULL_NAME: esc(personal.fullName),
      ROLE_TITLE: esc(personal.roleTitle),
      SPECIALIZATION: esc(personal.specialization),
      PRIMARY_DOMAIN: esc(personal.primaryDomain),
      LOCATION: esc(personal.location),
      CITY_COUNTRY: esc(personal.cityCountry),
      EMAIL: esc(personal.email),
      PHONE: esc(personal.phone),
      LINKEDIN_URL: esc(personal.linkedinUrl),
      SHORT_PROFILE_SUMMARY: esc(personal.shortProfileSummary),
      PROFESSIONAL_SUMMARY: esc(personal.professionalSummary),
      FOOTER_TAGLINE: esc(personal.footerTagline),
      ADDITIONAL_NOTE: esc(personal.additionalNote)
    });

    return html.replace(/<!--CVB:[\s\S]*?-->/g, '').replace(/\{\{[A-Z0-9_]+\}\}/g, '');
  }

  window.CVB = window.CVB || { templates: {} };
  window.CVB.templates = window.CVB.templates || {};
  window.CVB.templates[ID] = { id: ID, name: NAME, render: render };
}());
